import{_ as a,o,c as t,an as s}from"./chunks/framework.CiKXS6ao.js";const f=JSON.parse('{"title":"Release notes","description":"","frontmatter":{},"headers":[],"relativePath":"release-notes.md","filePath":"release-notes.md","lastUpdated":null}'),d={name:"release-notes.md"};function c(n,e,r,i,l,p){return o(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="Release-notes" tabindex="-1">Release notes <a class="header-anchor" href="#Release-notes" aria-label="Permalink to &quot;Release notes {#Release-notes}&quot;">​</a></h1><p>EpiAwarePackageTools.jl follows a hybrid changelog approach:</p><ul><li><p><strong>GitHub Releases</strong>: All releases (automatically generated by TagBot)</p></li><li><p><strong>NEWS.md</strong>: Major releases requiring detailed context (shown below)</p></li></ul><p>See <a href="https://github.com/EpiAware/EpiAwarePackageTools.jl/releases" target="_blank" rel="noreferrer">GitHub Releases</a> for minor/patch release information.</p><h2 id="Unreleased" tabindex="-1">Unreleased <a class="header-anchor" href="#Unreleased" aria-label="Permalink to &quot;Unreleased {#Unreleased}&quot;">​</a></h2><p><strong>Breaking</strong>: <code>scaffold_update</code> is renamed back to <code>update</code>, and is now <code>public</code>, not <code>export</code>ed (#294). A bare <code>using EpiAwarePackageTools</code> no longer brings it into scope — call it as <code>EpiAwarePackageTools.update(...)</code> or <code>using EpiAwarePackageTools: update</code>.</p><p>This function used to be a bare <code>update</code> until #173 found that an <code>export</code>ed generic verb collides with a package&#39;s own same-named export: <code>using EpiAwarePackageTools; using ComposedDistributions</code> left <code>update</code> unbound in <code>Main</code>, breaking Documenter <code>@ref</code> resolution across every kit-adopting package that also ships its own <code>update</code>. #178 fixed it at the time with a hard rename to <code>scaffold_update</code>. <code>public</code> closes that collision a different way: a <code>public</code>-not-<code>export</code>ed name is never brought into scope by a bare <code>using</code>, so it cannot fight another package&#39;s export regardless of what either package calls its own verb — that makes the short, generic name safe again, so #294 renames it back.</p><p><code>scaffold_update</code> is kept <code>public</code> too, as a transitional alias (<code>const scaffold_update = update</code>) — an already-qualified caller (<code>EpiAwarePackageTools.scaffold_update(...)</code>, or an explicit <code>using EpiAwarePackageTools: scaffold_update</code>) keeps working unchanged. The alias is removed in a future cleanup once adopters have moved onto <code>update</code>.</p><p>Every template-sync/self-drift caller shipped by the kit now calls <code>update</code>; an adopter on an older scaffolded <code>.github/workflows/template-sync.yaml</code> (calling <code>scaffold_update(...)</code> unqualified after a bare <code>using EpiAwarePackageTools</code>) needs a one-line fix — qualify the call — before their first sync on this kit version, or the sync run itself fails.</p>',9)])])}const g=a(d,[["render",c]]);export{f as __pageData,g as default};
